                    </div>
                  </div>
                </div>
              )}

              {/* NOTES TAB */}
              {careTab === 'notes' && (
                <div className="space-y-6 animate-in fade-in">
                  <div className="bg-slate-50 dark:bg-slate-900/50 p-4 rounded-xl border border-slate-200 dark:border-slate-700">
                    <h4 className="text-sm font-bold text-slate-700 dark:text-slate-300 mb-3">{t('admissions_care_add_note')}</h4>
                    <form onSubmit={handleAddNote} className="space-y-3">
                      <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                        <Input placeholder={t('admissions_care_vitals_bp')} value={noteForm.bp} onChange={e => setNoteForm({...noteForm, bp: e.target.value})} className="bg-white dark:bg-slate-800" />
                        <Input placeholder={t('admissions_care_vitals_temp')} type="number" value={noteForm.temp} onChange={e => setNoteForm({...noteForm, temp: e.target.value})} className="bg-white dark:bg-slate-800" />
                        <Input placeholder={t('admissions_care_vitals_pulse')} type="number" value={noteForm.pulse} onChange={e => setNoteForm({...noteForm, pulse: e.target.value})} className="bg-white dark:bg-slate-800" />
                        <Input placeholder={t('admissions_care_vitals_resp')} type="number" value={noteForm.resp} onChange={e => setNoteForm({...noteForm, resp: e.target.value})} className="bg-white dark:bg-slate-800" />
                      </div>
                      <div className="flex gap-2">
                        <div className="flex-1">
                          <Textarea placeholder={t('admissions_care_observations_placeholder')} rows={2} value={noteForm.note} onChange={e => setNoteForm({...noteForm, note: e.target.value})} className="bg-white dark:bg-slate-800" />
                        </div>
                        <Button type="submit" icon={Plus} className="self-end h-[50px]">{t('admissions_care_save_note_button')}</Button>
                      </div>
                    </form>
                  </div>

                  <div className="space-y-3 max-h-[300px] overflow-y-auto pr-1 custom-scrollbar">
                    {inpatientDetails.notes && inpatientDetails.notes.length > 0 ? (
                      inpatientDetails.notes.map((note: any) => (
                        <div key={note.id} className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-100 dark:border-slate-700 relative">
                          <div className="flex justify-between mb-2">
                            <span className="text-xs font-bold text-primary-600 flex items-center gap-1"><User size={12}/> Dr. {note.doctorName}</span>
                            <span className="text-xs text-gray-400">{new Date(note.created_at).toLocaleString()}</span>
                          </div>
                          <p className="text-sm text-gray-800 dark:text-gray-200 mb-3">{note.note}</p>
                          {note.vitals && (
                            <div className="flex gap-3 text-xs text-gray-500 bg-slate-50 dark:bg-slate-900/50 p-2 rounded-lg w-fit">
                              {note.vitals.bp && <span className="flex items-center gap-1"><Activity size={10}/> BP: {note.vitals.bp}</span>}
                              {note.vitals.temp && <span className="flex items-center gap-1"><Thermometer size={10}/> {note.vitals.temp}°C</span>}
                              {note.vitals.pulse && <span className="flex items-center gap-1"><HeartPulse size={10}/> {note.vitals.pulse} bpm</span>}
                            </div>
                          )}
                        </div>
                      ))
                    ) : (
                      <div className="text-center py-8 text-gray-400">{t('admissions_care_no_notes')}</div>
                    )}
                  </div>
                </div>
              )}

              {/* DISCHARGE TAB */}
              {careTab === 'discharge' && (
                <div className="space-y-6 animate-in fade-in">
                  <div className="bg-yellow-50 dark:bg-yellow-900/20 p-4 rounded-xl border border-yellow-100 dark:border-yellow-900/50 flex gap-3">
                    <AlertCircle className="text-yellow-600 shrink-0 mt-0.5" />
                    <div>
                      <h4 className="font-bold text-yellow-800 dark:text-yellow-500 text-sm">{t('admissions_care_discharge_process')}</h4>
                      <p className="text-xs text-yellow-700 dark:text-yellow-400 mt-1">{t('admissions_care_discharge_note')}</p>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="bg-slate-50 dark:bg-slate-900 p-4 rounded-xl space-y-3">
                      <h4 className="font-bold text-sm text-gray-700 dark:text-gray-300 uppercase tracking-wider mb-2">{t('admissions_modal_discharge_summary_title')}</h4>
                      <div className="flex justify-between text-sm">
                        <span>{t('admissions_care_total_stay')}</span>
                        <span className="font-bold">{inpatientDetails.daysStayed} days</span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span>{t('admissions_care_estimated_bill')}</span>
                        <span className="font-mono font-bold">${inpatientDetails.estimatedBill.toLocaleString()}</span>
                      </div>
                      <div className="flex justify-between text-sm pt-2 border-t border-slate-200 dark:border-slate-700">
                         <span className="text-red-600 font-bold">{t('admissions_care_balance_due')}</span>
                         <span className="font-mono font-bold text-red-600">${(inpatientDetails.outstandingBalance + inpatientDetails.estimatedBill).toLocaleString()}</span>
                      </div>
                    </div>

                    <div className="space-y-4">
                      <div>
                        <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-1">{t('admissions_care_discharge_status')}</label>
                        <Select value={dischargeForm.status} onChange={e => setDischargeForm({...dischargeForm, status: e.target.value})}>
                          <option value="Recovered">{t('admissions_care_discharge_status_recovered')}</option>
                          <option value="Transferred">{t('admissions_care_discharge_status_transferred')}</option>
                          <option value="AMA">{t('admissions_care_discharge_status_ama')}</option>
                          <option value="Deceased">{t('admissions_care_discharge_status_deceased')}</option>
                        </Select>
                      </div>
                      <Textarea 
                        label={t('admissions_care_discharge_summary')} 
                        rows={3} 
                        value={dischargeForm.notes} 
                        onChange={e => setDischargeForm({...dischargeForm, notes: e.target.value})}
                      />
                    </div>
                  </div>

                  <div className="flex justify-end pt-4 border-t dark:border-slate-700">
                    <Button variant="danger" icon={LogOut} onClick={handleDischarge}>
                      {t('admissions_discharge_button')}
                    </Button>
                  </div>
                </div>
              )}

            </div>
          </div>

          <div className="flex justify-end pt-4 border-t border-gray-100 dark:border-slate-700 mt-4">
            <Button variant="secondary" onClick={() => setIsCareModalOpen(false)}>{t('close')}</Button>
          </div>
        </Modal>
      )}

      {/* Confirmation Dialog */}
      <ConfirmationDialog 
        isOpen={confirmState.isOpen}
        onClose={() => setConfirmState({ ...confirmState, isOpen: false })}
        onConfirm={confirmState.action}
        title={confirmState.title}
        message={confirmState.message}
        type={confirmState.type}
      />
    </div>
  );
};

const Database = require('better-sqlite3');
const path = require('path');
const fs = require('fs');

const dbPath = process.env.DB_PATH || path.join(__dirname, '../../allcare.db');
const db = new Database(dbPath); // verbose: console.log for debugging

// PERFORMANCE OPTIMIZATION: Enable Write-Ahead Logging (WAL)
db.pragma('journal_mode = WAL');
db.pragma('synchronous = NORMAL'); 
// ENABLE FOREIGN KEYS
db.pragma('foreign_keys = ON');

const initDB = (forceReset = false) => {
  if (forceReset) {
    console.log('Resetting database...');
    const dbFile = process.env.DB_PATH || path.join(__dirname, '../../allcare.db');
    if (fs.existsSync(dbFile)) {
        fs.unlinkSync(dbFile);
    }
    // Re-instantiate after delete
    return initDB(false);
  }

  // --- 1. Core & Access Control ---
  db.prepare(`
    CREATE TABLE IF NOT EXISTS users (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      username TEXT UNIQUE NOT NULL,
      password TEXT NOT NULL,
      full_name TEXT NOT NULL,
      role TEXT NOT NULL,
      email TEXT,
      phone TEXT,
      is_active BOOLEAN DEFAULT 1,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )
  `).run();

  db.prepare(`
    CREATE TABLE IF NOT EXISTS role_permissions (
      role TEXT PRIMARY KEY,
      permissions TEXT NOT NULL, -- JSON array
      updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )
  `).run();

  // --- 2. Medical Staff (Moved UP before appointments/HR to satisfy FKs) ---
  db.prepare(`
    CREATE TABLE IF NOT EXISTS medical_staff (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      employee_id TEXT UNIQUE NOT NULL,
      full_name TEXT NOT NULL,
      type TEXT NOT NULL,
      department TEXT,
      specialization TEXT,
      consultation_fee REAL DEFAULT 0,
      consultation_fee_followup REAL DEFAULT 0,
      consultation_fee_emergency REAL DEFAULT 0,
      status TEXT CHECK(status IN ('active', 'inactive', 'dismissed')) DEFAULT 'active',
      is_available BOOLEAN DEFAULT 1,
      available_days TEXT, -- JSON array
      available_time_start TEXT,
      available_time_end TEXT,
      email TEXT,
      phone TEXT,
      address TEXT,
      base_salary REAL DEFAULT 0,
      join_date DATE,
      bank_details TEXT,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )
  `).run();

  // MIGRATION: Ensure 'address' column exists in medical_staff for existing databases
  try {
    db.prepare('SELECT address FROM medical_staff LIMIT 1').get();
  } catch (error) {
    if (error.message.includes('no such column')) {
        console.log('Migrating database: Adding missing address column to medical_staff table...');
        try {
          db.prepare('ALTER TABLE medical_staff ADD COLUMN address TEXT').run();
        } catch (e) {
          console.error('Migration failed:', e);
        }
    }
  }

  // --- 3. Patient & Clinical Records ---
  db.prepare(`
    CREATE TABLE IF NOT EXISTS patients (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      patient_id TEXT UNIQUE NOT NULL,
      full_name TEXT NOT NULL,
      phone TEXT NOT NULL,
      address TEXT,
      age INTEGER,
      gender TEXT,
      type TEXT DEFAULT 'outpatient',
      symptoms TEXT,
      medical_history TEXT,
      allergies TEXT,
      blood_group TEXT,
      emergency_contacts TEXT, -- JSON object
      has_insurance BOOLEAN DEFAULT 0,
      insurance_details TEXT, -- JSON object
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )
  `).run();

  db.prepare(`
    CREATE TABLE IF NOT EXISTS appointments (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      appointment_number TEXT UNIQUE NOT NULL,
      patient_id INTEGER NOT NULL,
      medical_staff_id INTEGER NOT NULL,
      appointment_datetime DATETIME NOT NULL,
      type TEXT DEFAULT 'Consultation',
      status TEXT DEFAULT 'pending',
      billing_status TEXT DEFAULT 'unbilled',
      reason TEXT,
      bill_id INTEGER DEFAULT NULL,
      daily_token INTEGER,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY(patient_id) REFERENCES patients(id),
      FOREIGN KEY(medical_staff_id) REFERENCES medical_staff(id)
    )
  `).run();

  // --- 4. Human Resources (HR) ---
  db.prepare(`
    CREATE TABLE IF NOT EXISTS hr_attendance (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      staff_id INTEGER NOT NULL,
      date DATE NOT NULL,
      status TEXT CHECK(status IN ('present', 'absent', 'late', 'half_day')) DEFAULT 'present',
      check_in TIME,
      check_out TIME,
      FOREIGN KEY(staff_id) REFERENCES medical_staff(id)
    )
  `).run();

  db.prepare(`
    CREATE TABLE IF NOT EXISTS hr_leaves (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      staff_id INTEGER NOT NULL,
      type TEXT CHECK(type IN ('sick', 'vacation', 'casual', 'unpaid')) NOT NULL,
      start_date DATE NOT NULL,
      end_date DATE NOT NULL,
      reason TEXT,
      status TEXT CHECK(status IN ('pending', 'approved', 'rejected')) DEFAULT 'pending',
      FOREIGN KEY(staff_id) REFERENCES medical_staff(id)
    )
  `).run();

  db.prepare(`
    CREATE TABLE IF NOT EXISTS hr_payroll (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      staff_id INTEGER NOT NULL,
      month TEXT NOT NULL,
      base_salary REAL NOT NULL,
      total_bonuses REAL DEFAULT 0,
      total_fines REAL DEFAULT 0,
      net_salary REAL NOT NULL,
      status TEXT DEFAULT 'draft',
      generated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY(staff_id) REFERENCES medical_staff(id)
    )
  `).run();

  db.prepare(`
    CREATE TABLE IF NOT EXISTS hr_financials (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      staff_id INTEGER NOT NULL,
      type TEXT CHECK(type IN ('bonus', 'fine', 'loan')) NOT NULL,
      amount REAL NOT NULL,
      reason TEXT,
      date DATE NOT NULL,
      status TEXT DEFAULT 'active',
      FOREIGN KEY(staff_id) REFERENCES medical_staff(id)
    )
  `).run();

  // --- 5. Billing & Financials ---
  db.prepare(`
    CREATE TABLE IF NOT EXISTS billing (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      bill_number TEXT UNIQUE NOT NULL,
      patient_id INTEGER NOT NULL,
      total_amount REAL NOT NULL,
      paid_amount REAL DEFAULT 0,
      status TEXT DEFAULT 'pending',
      bill_date DATETIME DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY(patient_id) REFERENCES patients(id)
    )
  `).run();

  db.prepare(`
    CREATE TABLE IF NOT EXISTS billing_items (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      billing_id INTEGER NOT NULL,
      description TEXT NOT NULL,
      amount REAL NOT NULL,
      FOREIGN KEY(billing_id) REFERENCES billing(id)
    )
  `).run();

  // --- TREASURY (New) ---
  db.prepare(`
    CREATE TABLE IF NOT EXISTS transactions (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      type TEXT CHECK(type IN ('income', 'expense')) NOT NULL,
      category TEXT,
      amount REAL NOT NULL,
      method TEXT,
      reference_id INTEGER, -- bill_id for income
      details TEXT, -- JSON for insurance/trans details
      date DATETIME DEFAULT CURRENT_TIMESTAMP,
      description TEXT
    )
  `).run();

  // --- 6. Medical Services & Wards ---
  db.prepare(`CREATE TABLE IF NOT EXISTS lab_tests (id INTEGER PRIMARY KEY, name_en TEXT, name_ar TEXT, category_en TEXT, category_ar TEXT, cost REAL, normal_range TEXT)`).run();

  db.prepare(`CREATE TABLE IF NOT EXISTS lab_requests (id INTEGER PRIMARY KEY, patient_id INTEGER, test_ids TEXT, status TEXT, projected_cost REAL, bill_id INTEGER, created_at DATETIME DEFAULT CURRENT_TIMESTAMP)`).run();

  db.prepare(`CREATE TABLE IF NOT EXISTS nurse_services (id INTEGER PRIMARY KEY, name_en TEXT, name_ar TEXT, description_en TEXT, description_ar TEXT, cost REAL)`).run();

  db.prepare(`CREATE TABLE IF NOT EXISTS nurse_requests (id INTEGER PRIMARY KEY, patient_id INTEGER, staff_id INTEGER, service_name TEXT, cost REAL, notes TEXT, status TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP)`).run();

  db.prepare(`CREATE TABLE IF NOT EXISTS operations_catalog (id INTEGER PRIMARY KEY, name_en TEXT, name_ar TEXT, base_cost REAL)`).run();

  db.prepare(`CREATE TABLE IF NOT EXISTS operations (id INTEGER PRIMARY KEY, patient_id INTEGER, operation_name TEXT, doctor_id INTEGER, notes TEXT, status TEXT, projected_cost REAL, bill_id INTEGER, cost_details TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP)`).run();

  db.prepare(`CREATE TABLE IF NOT EXISTS beds (id INTEGER PRIMARY KEY, room_number TEXT, type TEXT, status TEXT, cost_per_day REAL)`).run();

  db.prepare(`CREATE TABLE IF NOT EXISTS admissions (id INTEGER PRIMARY KEY, patient_id INTEGER, bed_id INTEGER, doctor_id INTEGER, entry_date DATETIME, discharge_date DATETIME, actual_discharge_date DATETIME, status TEXT, notes TEXT, discharge_notes TEXT, discharge_status TEXT, projected_cost REAL, bill_id INTEGER)`).run();

  db.prepare(`CREATE TABLE IF NOT EXISTS inpatient_notes (id INTEGER PRIMARY KEY, admission_id INTEGER, doctor_id INTEGER, note TEXT, vitals TEXT, created_at DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(admission_id) REFERENCES admissions(id))`).run();

  // --- 7. System Configuration ---
  db.prepare(`CREATE TABLE IF NOT EXISTS departments (id INTEGER PRIMARY KEY, name_en TEXT, name_ar TEXT, description_en TEXT, description_ar TEXT)`).run();

  db.prepare(`CREATE TABLE IF NOT EXISTS specializations (id INTEGER PRIMARY KEY, name_en TEXT, name_ar TEXT, description_en TEXT, description_ar TEXT, related_role TEXT)`).run();

  db.prepare(`CREATE TABLE IF NOT EXISTS system_settings (key TEXT PRIMARY KEY, value TEXT)`).run();
  db.prepare(`CREATE TABLE IF NOT EXISTS tax_rates (id INTEGER PRIMARY KEY, name_en TEXT, name_ar TEXT, rate REAL, is_active BOOLEAN)`).run();
  db.prepare(`CREATE TABLE IF NOT EXISTS payment_methods (id INTEGER PRIMARY KEY, name_en TEXT, name_ar TEXT, is_active BOOLEAN)`).run();
  db.prepare(`CREATE TABLE IF NOT EXISTS insurance_providers (id INTEGER PRIMARY KEY, name_en TEXT, name_ar TEXT, is_active BOOLEAN)`).run();
  db.prepare(`CREATE TABLE IF NOT EXISTS banks (id INTEGER PRIMARY KEY AUTOINCREMENT, name_en TEXT, name_ar TEXT, is_active BOOLEAN DEFAULT 1)`).run();

  // --- Seeding ---
  seedData();
};

